import React, { useState } from 'react';
import { Container, Card, Form, Button, Row, Col, Alert } from 'react-bootstrap';
import { LinkContainer } from 'react-router-bootstrap';

const DietForm = () => {
  const [formData, setFormData] = useState({
    weight: '',
    height: '',
    age: '',
    gender: '',
    activityLevel: '',
    goal: '',
    dietaryRestrictions: [],
    allergies: '',
    mealsPerDay: '3',
    waterIntake: '8',
    sleepHours: '',
    medicalConditions: ''
  });
  const [recommendation, setRecommendation] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    if (type === 'checkbox') {
      setFormData(prev => ({
        ...prev,
        dietaryRestrictions: checked 
          ? [...prev.dietaryRestrictions, value]
          : prev.dietaryRestrictions.filter(item => item !== value)
      }));
    } else {
      setFormData({
        ...formData,
        [name]: value
      });
    }
  };

  const calculateBMI = () => {
    const weight = parseFloat(formData.weight);
    const height = parseFloat(formData.height) / 100; // Convert cm to m
    if (weight && height) {
      return (weight / (height * height)).toFixed(1);
    }
    return null;
  };

  const generateRecommendation = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));
      
      const bmi = calculateBMI();
      const dailyCalories = calculateDailyCalories();
      
      setRecommendation({
        bmi: bmi,
        dailyCalories: dailyCalories,
        protein: Math.round(dailyCalories * 0.3 / 4),
        carbs: Math.round(dailyCalories * 0.4 / 4),
        fats: Math.round(dailyCalories * 0.3 / 9),
        mealPlan: generateMealPlan(),
        tips: generateTips()
      });
      
    } catch (err) {
      setError('Failed to generate recommendation. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const calculateDailyCalories = () => {
    const weight = parseFloat(formData.weight);
    const height = parseFloat(formData.height);
    const age = parseFloat(formData.age);
    const gender = formData.gender;
    const activityLevel = formData.activityLevel;
    const goal = formData.goal;

    if (!weight || !height || !age || !gender || !activityLevel || !goal) {
      return 0;
    }

    // Harris-Benedict Equation
    let bmr;
    if (gender === 'male') {
      bmr = 88.362 + (13.397 * weight) + (4.799 * height) - (5.677 * age);
    } else {
      bmr = 447.593 + (9.247 * weight) + (3.098 * height) - (4.330 * age);
    }

    // Activity multiplier
    const activityMultipliers = {
      sedentary: 1.2,
      light: 1.375,
      moderate: 1.55,
      active: 1.725,
      veryActive: 1.9
    };

    let tdee = bmr * (activityMultipliers[activityLevel] || 1.2);

    // Goal adjustment
    if (goal === 'weightLoss') {
      tdee -= 500; // 500 calorie deficit for weight loss
    } else if (goal === 'weightGain') {
      tdee += 500; // 500 calorie surplus for weight gain
    }

    return Math.round(tdee);
  };

  const generateMealPlan = () => {
    const meals = {
      breakfast: ['Oatmeal with berries and nuts', 'Greek yogurt with granola', 'Whole grain toast with avocado and eggs'],
      lunch: ['Grilled chicken salad', 'Quinoa bowl with vegetables', 'Turkey wrap with hummus'],
      dinner: ['Baked salmon with roasted vegetables', 'Lean beef stir-fry', 'Vegetarian pasta with tomato sauce'],
      snacks: ['Apple with almond butter', 'Mixed nuts', 'Protein smoothie', 'Carrot sticks with hummus']
    };

    return meals;
  };

  const generateTips = () => {
    return [
      'Drink at least 8 glasses of water per day',
      'Include a variety of colorful vegetables in your diet',
      'Choose whole grains over refined grains',
      'Limit processed foods and added sugars',
      'Practice mindful eating and portion control'
    ];
  };

  return (
    <Container className="diet-form-container">
      <h2 className="text-center mb-4">Personalized Diet Plan</h2>
      
      <Card className="mb-4">
        <Card.Body>
          <Form onSubmit={generateRecommendation}>
            <Row>
              <Col md={3}>
                <Form.Group className="mb-3">
                  <Form.Label>Weight (kg)</Form.Label>
                  <Form.Control
                    type="number"
                    name="weight"
                    value={formData.weight}
                    onChange={handleChange}
                    placeholder="Enter weight"
                    required
                  />
                </Form.Group>
              </Col>
              <Col md={3}>
                <Form.Group className="mb-3">
                  <Form.Label>Height (cm)</Form.Label>
                  <Form.Control
                    type="number"
                    name="height"
                    value={formData.height}
                    onChange={handleChange}
                    placeholder="Enter height"
                    required
                  />
                </Form.Group>
              </Col>
              <Col md={3}>
                <Form.Group className="mb-3">
                  <Form.Label>Age</Form.Label>
                  <Form.Control
                    type="number"
                    name="age"
                    value={formData.age}
                    onChange={handleChange}
                    placeholder="Enter age"
                    required
                  />
                </Form.Group>
              </Col>
              <Col md={3}>
                <Form.Group className="mb-3">
                  <Form.Label>Gender</Form.Label>
                  <Form.Select
                    name="gender"
                    value={formData.gender}
                    onChange={handleChange}
                    required
                  >
                    <option value="">Select</option>
                    <option value="male">Male</option>
                    <option value="female">Female</option>
                  </Form.Select>
                </Form.Group>
              </Col>
            </Row>

            <Row>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Activity Level</Form.Label>
                  <Form.Select
                    name="activityLevel"
                    value={formData.activityLevel}
                    onChange={handleChange}
                    required
                  >
                    <option value="">Select activity level</option>
                    <option value="sedentary">Sedentary (little or no exercise)</option>
                    <option value="light">Lightly active (1-3 days/week)</option>
                    <option value="moderate">Moderately active (3-5 days/week)</option>
                    <option value="active">Very active (6-7 days/week)</option>
                    <option value="veryActive">Extra active (very hard exercise)</option>
                  </Form.Select>
                </Form.Group>
              </Col>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Health Goal</Form.Label>
                  <Form.Select
                    name="goal"
                    value={formData.goal}
                    onChange={handleChange}
                    required
                  >
                    <option value="">Select your goal</option>
                    <option value="weightLoss">Weight Loss</option>
                    <option value="maintenance">Maintain Weight</option>
                    <option value="weightGain">Weight Gain</option>
                    <option value="muscleGain">Muscle Gain</option>
                  </Form.Select>
                </Form.Group>
              </Col>
            </Row>

            <Form.Group className="mb-3">
              <Form.Label>Dietary Restrictions</Form.Label>
              <div>
                {['vegetarian', 'vegan', 'glutenFree', 'dairyFree', 'keto', 'paleo'].map(restriction => (
                  <Form.Check
                    key={restriction}
                    type="checkbox"
                    label={restriction.charAt(0).toUpperCase() + restriction.slice(1).replace(/([A-Z])/g, ' $1')}
                    name="dietaryRestrictions"
                    value={restriction}
                    checked={formData.dietaryRestrictions.includes(restriction)}
                    onChange={handleChange}
                    inline
                  />
                ))}
              </div>
            </Form.Group>

            <Row>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Allergies (if any)</Form.Label>
                  <Form.Control
                    type="text"
                    name="allergies"
                    value={formData.allergies}
                    onChange={handleChange}
                    placeholder="e.g., nuts, shellfish, etc."
                  />
                </Form.Group>
              </Col>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Medical Conditions</Form.Label>
                  <Form.Control
                    type="text"
                    name="medicalConditions"
                    value={formData.medicalConditions}
                    onChange={handleChange}
                    placeholder="e.g., diabetes, hypertension, etc."
                  />
                </Form.Group>
              </Col>
            </Row>

            <Row>
              <Col md={4}>
                <Form.Group className="mb-3">
                  <Form.Label>Meals Per Day</Form.Label>
                  <Form.Select
                    name="mealsPerDay"
                    value={formData.mealsPerDay}
                    onChange={handleChange}
                  >
                    <option value="3">3 meals</option>
                    <option value="4">4 meals</option>
                    <option value="5">5 meals</option>
                    <option value="6">6 meals</option>
                  </Form.Select>
                </Form.Group>
              </Col>
              <Col md={4}>
                <Form.Group className="mb-3">
                  <Form.Label>Water Intake (glasses/day)</Form.Label>
                  <Form.Control
                    type="number"
                    name="waterIntake"
                    value={formData.waterIntake}
                    onChange={handleChange}
                    min="1"
                    max="20"
                  />
                </Form.Group>
              </Col>
              <Col md={4}>
                <Form.Group className="mb-3">
                  <Form.Label>Sleep Hours</Form.Label>
                  <Form.Control
                    type="number"
                    name="sleepHours"
                    value={formData.sleepHours}
                    onChange={handleChange}
                    placeholder="Hours per night"
                    min="1"
                    max="24"
                  />
                </Form.Group>
              </Col>
            </Row>

            {error && <Alert variant="danger">{error}</Alert>}

            <Button
              variant="primary"
              type="submit"
              className="w-100"
              disabled={loading}
            >
              {loading ? 'Generating Recommendation...' : 'Get Diet Recommendation'}
            </Button>
          </Form>
        </Card.Body>
      </Card>

      {recommendation && (
        <Card className="recommendation-card">
          <Card.Body>
            <h3 className="mb-4">Your Personalized Diet Recommendation</h3>
            
            <Row className="mb-4">
              <Col md={3}>
                <div className="text-center">
                  <h5>BMI</h5>
                  <h2>{recommendation.bmi}</h2>
                </div>
              </Col>
              <Col md={3}>
                <div className="text-center">
                  <h5>Daily Calories</h5>
                  <h2>{recommendation.dailyCalories}</h2>
                </div>
              </Col>
              <Col md={2}>
                <div className="text-center">
                  <h5>Protein (g)</h5>
                  <h2>{recommendation.protein}</h2>
                </div>
              </Col>
              <Col md={2}>
                <div className="text-center">
                  <h5>Carbs (g)</h5>
                  <h2>{recommendation.carbs}</h2>
                </div>
              </Col>
              <Col md={2}>
                <div className="text-center">
                  <h5>Fats (g)</h5>
                  <h2>{recommendation.fats}</h2>
                </div>
              </Col>
            </Row>

            <h4 className="mb-3">Sample Meal Plan</h4>
            <Row>
              <Col md={6}>
                <h6>Breakfast Options:</h6>
                <ul>
                  {recommendation.mealPlan.breakfast.map((meal, index) => (
                    <li key={index}>{meal}</li>
                  ))}
                </ul>
              </Col>
              <Col md={6}>
                <h6>Lunch Options:</h6>
                <ul>
                  {recommendation.mealPlan.lunch.map((meal, index) => (
                    <li key={index}>{meal}</li>
                  ))}
                </ul>
              </Col>
              <Col md={6}>
                <h6>Dinner Options:</h6>
                <ul>
                  {recommendation.mealPlan.dinner.map((meal, index) => (
                    <li key={index}>{meal}</li>
                  ))}
                </ul>
              </Col>
              <Col md={6}>
                <h6>Snack Options:</h6>
                <ul>
                  {recommendation.mealPlan.snacks.map((snack, index) => (
                    <li key={index}>{snack}</li>
                  ))}
                </ul>
              </Col>
            </Row>

            <h4 className="mb-3 mt-4">Health Tips</h4>
            <ul>
              {recommendation.tips.map((tip, index) => (
                <li key={index}>{tip}</li>
              ))}
            </ul>

            <div className="text-center mt-4">
              <LinkContainer to="/dashboard">
                <Button variant="light" size="lg">View Dashboard</Button>
              </LinkContainer>
            </div>
          </Card.Body>
        </Card>
      )}
    </Container>
  );
};

export default DietForm;
